import axios from 'axios';
import { toast } from 'react-toastify';

const API_BASE_URL = 'https://soni.loyalstring.co.in/api/ProductMaster';

// Create axios instance with default config
const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'X-XSS-Protection': '1; mode=block',
  },
});

// Request interceptor
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Response interceptor
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response) {
      switch (error.response.status) {
        case 401:
          localStorage.removeItem('token');
          localStorage.removeItem('userInfo');
          window.location.href = '/login?session_expired=true';
          break;
        case 429:
          toast.error('Too many requests. Please try again later.');
          break;
        case 503:
          toast.error('Service temporarily unavailable. Please try again later.');
          break;
        default:
          toast.error(error.response.data?.Message || 'An error occurred');
      }
    } else if (error.request) {
      toast.error('Network error. Please check your connection.');
    } else {
      toast.error('An unexpected error occurred.');
    }
    return Promise.reject(error);
  }
);

// Rate limiting
const rateLimiter = {
  timestamps: [],
  limit: 100, // requests
  interval: 60000, // 1 minute in milliseconds

  checkLimit() {
    const now = Date.now();
    this.timestamps = this.timestamps.filter(time => (now - time) < this.interval);
    if (this.timestamps.length >= this.limit) {
      throw new Error('Rate limit exceeded');
    }
    this.timestamps.push(now);
  }
};

// API methods with rate limiting
export const rfidService = {
  async login(credentials) {
    rateLimiter.checkLimit();
    return api.post('/AuthLogin', credentials);
  },

  async saveRFIDTransaction(data) {
    rateLimiter.checkLimit();
    return api.post('/SaveRFIDTransactionDetails', data);
  },

  async getRFIDDetails(data) {
    rateLimiter.checkLimit();
    return api.post('/GetAllRFIDDetails', data);
  },

  async deleteRFID(data) {
    rateLimiter.checkLimit();
    return api.post('/DeleteRFIDByClientAndDevice', data);
  }
};
